import{_ as e,o as a,c as t,R as o}from"./chunks/framework.g9eZ-ZSs.js";const f=JSON.parse('{"title":"Entity Models","description":"","frontmatter":{},"headers":[],"relativePath":"modeling/model-types/entities.md","filePath":"modeling/model-types/entities.md"}'),r={name:"modeling/model-types/entities.md"},s=o('<h1 id="entity-models" tabindex="-1">Entity Models <a class="header-anchor" href="#entity-models" aria-label="Permalink to &quot;Entity Models&quot;">​</a></h1><p>Models are the core business objects of your application - they serve as the fundamental representation of data in your application. The design of your models is very important. In <a href="https://docs.microsoft.com/en-us/ef/core/" target="_blank" rel="noreferrer">Entity Framework Core</a> (EF), data models are just Plain Old CLR Objects (POCOs).</p><h2 id="building-a-data-model" tabindex="-1">Building a Data Model <a class="header-anchor" href="#building-a-data-model" aria-label="Permalink to &quot;Building a Data Model&quot;">​</a></h2><p>To start building your data model that Coalesce will generate code for, follow the best practices for <a href="https://docs.microsoft.com/en-us/ef/core/" target="_blank" rel="noreferrer">EF Core</a>. Guidance on this topic is available in abundance in the <a href="https://docs.microsoft.com/en-us/ef/core/" target="_blank" rel="noreferrer">Entity Framework Core documentation</a>.</p><p>Don&#39;t worry about querying or saving data when you&#39;re just getting started - Coalesce will provide a lot of that functionality for you, and it is very easy to customize what Coalesce offers later. To get started, just build your POCOs and <code>DbContext</code> classes. Annotate your <code>DbContext</code> class with <code>[Coalesce]</code> so that Coalesce will discover it and generate code based off of your context for you.</p><p>Before you start building, you are highly encouraged to read the sections below. The linked pages explain in greater detail what Coalesce will build for you for each part of your data model.</p><h3 id="properties" tabindex="-1">Properties <a class="header-anchor" href="#properties" aria-label="Permalink to &quot;Properties&quot;">​</a></h3><p>Read <a href="/Coalesce/modeling/model-components/properties.html">Properties</a> for an outline of the different types of properties that you may place on your models and the code that Coalesce will generate for each of them.</p><h3 id="attributes" tabindex="-1">Attributes <a class="header-anchor" href="#attributes" aria-label="Permalink to &quot;Attributes&quot;">​</a></h3><p>Coalesce provides a number of C# attributes that can be used to decorate your model classes and their properties in order to customize behavior, appearance, security, and more. Coalesce also supports a number of annotations from <code>System.ComponentModel.DataAnnotations</code>.</p><p>Read <a href="/Coalesce/modeling/model-components/attributes.html">Attributes</a> to learn more.</p><h3 id="methods" tabindex="-1">Methods <a class="header-anchor" href="#methods" aria-label="Permalink to &quot;Methods&quot;">​</a></h3><p>You can place both static and interface methods on your model classes. Any public methods annotated with <a href="/Coalesce/modeling/model-components/attributes/coalesce.html">[Coalesce]</a> will have a generated API endpoint and corresponding generated TypeScript members for calling this API endpoint. Read <a href="/Coalesce/modeling/model-components/methods.html">Methods</a> to learn more.</p><h2 id="customizing-crud-operations" tabindex="-1">Customizing CRUD Operations <a class="header-anchor" href="#customizing-crud-operations" aria-label="Permalink to &quot;Customizing CRUD Operations&quot;">​</a></h2><p>Once you&#39;ve got a solid data model in place, its time to start customizing the way that Coalesce will <em>read</em> your data, as well as the way that it will handle your data when processing <em>creates</em>, <em>updates</em>, and <em>deletes</em>.</p><h3 id="data-sources" tabindex="-1">Data Sources <a class="header-anchor" href="#data-sources" aria-label="Permalink to &quot;Data Sources&quot;">​</a></h3><p>The method by which you can control what data the users of your application can access through Coalesce&#39;s generated APIs is by creating custom data sources. These are classes that allow complete control over the way that data is retrieved from your database and provided to clients. Read <a href="/Coalesce/modeling/model-components/data-sources.html">Data Sources</a> to learn more.</p><h3 id="behaviors" tabindex="-1">Behaviors <a class="header-anchor" href="#behaviors" aria-label="Permalink to &quot;Behaviors&quot;">​</a></h3><p>Behaviors in Coalesce are to mutating data as data sources are to reading data. Defining a behaviors class for a model allows complete control over the way that Coalesce will create, update, and delete your application&#39;s data in response to requests made through its generated API. Read <a href="/Coalesce/modeling/model-components/behaviors.html">Behaviors</a> to learn more.</p>',19),i=[s];function n(l,d,c,h,m,u){return a(),t("div",null,i)}const b=e(r,[["render",n]]);export{f as __pageData,b as default};
